/**
 * \brief The state of the request.
 *
 * Enum order must follow chronological order for state dependency check, @see hasReachedState().
 */
/** enum class tensorrt_llm::batch_manager::LlmRequestState */
public static final int
    /** Unknown state */
    kUNKNOWN = 0,
    /** Encoder phase starts (for encoder-decoder models) */
    kENCODER_INIT = 1,

    /** Waiting for scheduler to schedule the context-only request */
    kDISAGG_CONTEXT_WAIT_SCHEDULER = 7,
                                              /** e.g. in gen-first mode when generation request is not scheduled yet */
    /** New Generation request arrived at generation model */
    kDISAGG_GENERATION_INIT = 8,
    /** Transmitting the kv cache */
    kDISAGG_GENERATION_TRANS_IN_PROGRESS = 9,

    // schedulable states starts
    /** Context phase starts */
    kCONTEXT_INIT = 10,
    /** Context phase starts and cache transmission is in progress, */
    kDISAGG_CONTEXT_INIT_AND_TRANS = 11,
                                            /** used in layer-wise transmission */
    /** Kv cache transmission are finished */
    kDISAGG_GENERATION_TRANS_COMPLETE = 12,
    /** Generation phase is in progress */
    kGENERATION_IN_PROGRESS = 13,

    // schedulable states ends
    /** Generation phase is to be completed */
    kGENERATION_TO_COMPLETE = 14,
    /** Generation phase completed */
    kGENERATION_COMPLETE = 20,
    /** Waiting context-only request transmitting the kv cache, */
    kDISAGG_CONTEXT_TRANS_IN_PROGRESS = 21,
                                            /** after computation finished */
    /** Context-only request finished kv cache transmission. */
    kDISAGG_CONTEXT_COMPLETE = 22,
    /** Generation-only request waiting for ctx/draft tokens to be received */
    kDISAGG_GENERATION_WAIT_TOKENS = 23,

    // error states
    /** Error occurred during kv cache transmission */
    kDISAGG_TRANS_ERROR = -1;

/** enum tensorrt_llm::batch_manager::LlmRequestType */
public static final int
    LLMREQUEST_TYPE_CONTEXT_AND_GENERATION = 0, // Normal request will inference both context phase and generation phase
    LLMREQUEST_TYPE_CONTEXT_ONLY = 1,           // Only inference context phase
    LLMREQUEST_TYPE_GENERATION_ONLY = 2;         // only inference generation phase
